package com.back.capstone.controller;
import com.back.capstone.dto.AuthDtos.*;import com.back.capstone.service.UserService;import jakarta.validation.Valid;import java.nio.file.*;import org.springframework.core.io.*;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/users/me") public class UserController {private final UserService users;public UserController(UserService u){users=u;}@GetMapping UserResponse me(Authentication a){return users.me(a);}@PutMapping UserResponse update(Authentication a,@Valid @RequestBody UpdateProfileRequest r){return users.update(a,r);}@PutMapping("/password") ResponseEntity<Void> password(Authentication a,@Valid @RequestBody ChangePasswordRequest r){users.password(a,r);return ResponseEntity.noContent().build();}@PostMapping("/profile-image") UserResponse image(Authentication a,@RequestParam MultipartFile file){return users.image(a,file);}@GetMapping("/profile-image/content") ResponseEntity<Resource> content(Authentication a){Path p=users.profileImage(a);return ResponseEntity.ok().contentType(MediaType.IMAGE_JPEG).body(new FileSystemResource(p));}}
